starterCss:
/* Use :has() to:
   - Highlight form groups that contain an error span with a red left border
   - Style form groups containing a textarea differently (more height)
   - Give all form groups base styling */
.form-group {
  margin-bottom: 16px;
  padding: 12px;
  border: 1px solid #ddd;
  border-radius: 4px;
}
.input {
  display: block;
  width: 100%;
  padding: 8px;
  margin-top: 4px;
  border: 1px solid #ccc;
  border-radius: 4px;
  box-sizing: border-box;
}
.error {
  color: red;
  font-size: 12px;
  margin-top: 4px;
}

